mapper.insert:

	select
		'BA' || lpad(CAST(coalesce(max(CAST(substring(receipt_no, 3) AS INTEGER)), 0) + 1 AS VARCHAR), 8, '0')
	from uspt_bsns_pblanc_applcnt

/** UsptBsnsPblancApplcntDao.insert */
insert into uspt_bsns_pblanc_applcnt
	(
		apply_id
		, pblanc_id
		, rcept_odr
		, receipt_no
		, member_id
		, rcept_dt
		, rcept_sttus_cd
		, rcept_sttus_dt
		, makeup_opinion_cn
		, makeup_req_cn
		, reject_reason_cn
		, slctn
		, slctn_dt
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{applyId}
		, #{pblancId}
		, #{rceptOdr}
		, #{receiptNo}
		, #{memberId}
		, #{rceptDt}
		, #{rceptSttusCd}
		, #{rceptSttusDt}
		, #{makeupOpinionCn}
		, #{makeupReqCn}
		, #{rejectReasonCn}
		, #{slctn}
		, #{slctnDt}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptBsnsPblancApplcntDao.update */
update uspt_bsns_pblanc_applcnt
set
	pblanc_id				= #{pblancId}
	, rcept_odr				= #{rceptOdr}
	, receipt_no			= #{receiptNo}
	, member_id				= #{memberId}
	, apply_file_group_id	= #{applyFileGroupId}
	, rcept_dt				= #{rceptDt}
	, rcept_sttus_cd		= #{rceptSttusCd}
	, rcept_sttus_dt		= #{rceptSttusDt}
	, makeup_opinion_cn		= #{makeupOpinionCn}
	, makeup_req_cn			= #{makeupReqCn}
	, reject_reason_cn		= #{rejectReasonCn}
	, slctn					= #{slctn}
	, slctn_dt				= #{slctnDt}
	, updater_id			= #{updaterId}
	, updated_dt			= #{updatedDt}
where
	apply_id = #{applyId}

/** UsptBsnsPblancApplcntDao.updateRceptSttusCompt */
update uspt_bsns_pblanc_applcnt
set
	rcept_sttus_cd		= #{rceptSttusCd}
	, rcept_sttus_dt	= #{rceptSttusDt}
	, updater_id		= #{updaterId}
	, updated_dt		= #{updatedDt}
where
	apply_id = #{applyId}

sql.where:
ubpa.rcept_sttus_cd != 'TEMP'
and ubp.ordtm_rcrit = #{ordtmRcrit}

	and ub.bsns_year = #{bsnsYear}


	and ub.bsns_nm like concat('%', #{bsnsNm}, '%')


	and ubp.pblanc_nm like concat('%', #{pblancNm}, '%')


	and ubpa.rcept_sttus_cd = #{rceptSttusCd}




			and ubpa.receipt_no like concat('%', #{keyword}, '%')


			and cm.member_nm like concat('%', #{keyword}, '%')


			and ubpat.task_nm_ko like concat('%', #{keyword}, '%')

mapper.select:
/** UsptBsnsPblancApplcntDao.selectApplcntCount */
select
	count(*)
from uspt_bsns_pblanc_applcnt
where
	pblanc_id = #{pblancId}
	and member_id = #{memberId}

/** UsptBsnsPblancApplcntDao.selectEvlApplcntListCount */ select count(ubpa.apply_id) from uspt_bsns_pblanc_applcnt ubpa inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubpa.pblanc_id and ubpr.rcept_odr = ubpa.rcept_odr inner join uspt_evl_plan uep on uep.pblanc_id = ubpr.pblanc_id and uep.rcept_odr = ubpr.rcept_odr
inner join uspt_evl_step ues on ues.evl_plan_id = uep.evl_plan_id and ues.evl_step_id = #{evlStepId} inner join uspt_sect us on us.evl_plan_id = uep.evl_plan_id and us.sect_id = #{sectId} inner join uspt_evl_trget uet on uet.apply_id = ubpa.apply_id and uet.slctn = true and uet.evl_step_id = ues.evl_step_id and uet.sect_id = us.sect_id
inner join uspt_evl_last_slctn uels on uels.evl_plan_id = uep.evl_plan_id and uels.evl_last_slctn_id = #{evlLastSlctnId} inner join uspt_last_slctn_trget ulst on ulst.evl_last_slctn_id = uels.evl_last_slctn_id and ulst.apply_id = ubpa.apply_id and ulst.slctn = true

/** UsptBsnsPblancApplcntDao.selectEvlApplcntList */ select ubpa.apply_id , ubpa.receipt_no , ubpa.member_id , fn_cmm_get_member_nm(ubpa.member_id) as member_nm , ubpat.rspnber_nm from uspt_bsns_pblanc_applcnt ubpa inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubpa.pblanc_id and ubpr.rcept_odr = ubpa.rcept_odr inner join uspt_evl_plan uep on uep.pblanc_id = ubpr.pblanc_id and uep.rcept_odr = ubpr.rcept_odr
inner join uspt_evl_step ues on ues.evl_plan_id = uep.evl_plan_id and ues.evl_step_id = #{evlStepId} inner join uspt_sect us on us.evl_plan_id = uep.evl_plan_id and us.sect_id = #{sectId} inner join uspt_evl_trget uet on uet.apply_id = ubpa.apply_id and uet.slctn = true and uet.evl_step_id = ues.evl_step_id and uet.sect_id = us.sect_id
inner join uspt_evl_last_slctn uels on uels.evl_plan_id = uep.evl_plan_id and uels.evl_last_slctn_id = #{evlLastSlctnId} inner join uspt_last_slctn_trget ulst on ulst.evl_last_slctn_id = uels.evl_last_slctn_id and ulst.apply_id = ubpa.apply_id and ulst.slctn = true

/** UsptBsnsPblancApplcntDao.selectEntrpsSttusList */ select sub.apply_id , sub.bsns_cd , sub.bsns_nm , sub.bsns_year , sub.pblanc_id , sub.pblanc_nm , sub.task_nm_ko as task_nm , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@TASK_CODE_GROUP}', sub.task_type_cd) as task_type , sub.partcptn_div , sub.entrps_nm , sub.bizrno , sub.rspnber_nm , sub.enc_mbtlnum , sub.enc_email , sub.task_partcptn_entrprs_id , to_char(sub.recent_send_date, 'yyyy-mm-dd') as recent_send_date , row_number() over (order by sub.bsns_year desc, sub.bsns_nm, sub.pblanc_nm, sub.task_nm_ko) as rn from ( select ubpa.apply_id , ub.bsns_cd , ub.bsns_nm , ub.bsns_year , ubp.pblanc_id , ubp.pblanc_nm , ubpat.task_nm_ko , ubpat.task_type_cd , '주관업체' as partcptn_div , cm.member_nm as entrps_nm , cm.bizrno , ubpat.rspnber_nm , ubpat.enc_mbtlnum , ubpat.enc_email , ubpat.recent_send_date , '' as task_partcptn_entrprs_id from uspt_bsns_pblanc_applcnt ubpa inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubpa.pblanc_id and ubpr.rcept_odr = ubpa.rcept_odr inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpr.pblanc_id and ubp.enabled = true inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd and ub.enabled = true inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId} inner join cmmt_member cm on cm.member_id = ubpa.member_id where ubpa.slctn = true
and cm.member_nm like concat('%', #{entrpsNm}, '%')
and cm.bizrno like concat('%', #{bizrno}, '%')
and 1 = 0
union all select ubpa.apply_id , ub.bsns_cd , ub.bsns_nm , ub.bsns_year , ubp.pblanc_id , ubp.pblanc_nm , ubpat.task_nm_ko , ubpat.task_type_cd , '참여업체' as partcptn_div , utp.entrps_nm , '' as bizrno , utp.rspnber_nm , utp.enc_mbtlnum , utp.enc_email , utp.recent_send_date , utp.task_partcptn_entrprs_id from uspt_last_slctn_trget ulst inner join uspt_bsns_slctn ubs on ubs.last_slctn_trget_id = ulst.last_slctn_trget_id inner join uspt_bsns_plan_doc ubpd on ubpd.bsns_slctn_id = ubs.bsns_slctn_id inner join uspt_task_prtcmpny utp on utp.bsns_plan_doc_id = ubpd.bsns_plan_doc_id inner join uspt_evl_last_slctn uels on uels.evl_last_slctn_id = ulst.evl_last_slctn_id and uels.last_slctn = true inner join uspt_evl_plan uep on uep.evl_plan_id = uels.evl_plan_id and uep.evl_type_cd = '${@aicluster.pms.common.util.Code@EVL_TYPE_01_CODE}' and uep.evl_sttus_cd = '${@aicluster.pms.common.util.Code@EVL_STTUS_03_CODE}' inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = uep.pblanc_id and ubpr.rcept_odr = uep.rcept_odr inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpr.pblanc_id and ubp.enabled = true inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.pblanc_id = ubpr.pblanc_id and ubpa.rcept_odr = ubpr.rcept_odr and ubpa.apply_id = ulst.apply_id inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd and ub.enabled = true inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId} where ulst.slctn = true
and utp.entrps_nm like concat('%', #{entrpsNm}, '%')
and 1 = 0
and 1 = 0
) sub
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** UsptBsnsPblancApplcntDao.selectEntrpsSttusList */ select ubpa.apply_id , ubpat.enc_mbtlnum , ubpat.enc_email , ubpat.rspnber_nm , '' as task_partcptn_entrprs_id from uspt_bsns_pblanc_applcnt ubpa inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id where ubpa.slctn = true
and ubpa.apply_id in
#{item}
and 1 = 0
union all select ubpa.apply_id , utp.enc_mbtlnum , utp.enc_email , utp.rspnber_nm , utp.task_partcptn_entrprs_id from uspt_bsns_pblanc_applcnt ubpa inner join uspt_evl_plan uep on ubpa.pblanc_id = uep.pblanc_id and ubpa.rcept_odr = uep.rcept_odr and uep.evl_type_cd = '${@aicluster.pms.common.util.Code@EVL_TYPE_01_CODE}' and uep.evl_sttus_cd = '${@aicluster.pms.common.util.Code@EVL_STTUS_03_CODE}' inner join uspt_evl_last_slctn uels on uels.evl_plan_id = uep.evl_plan_id and uels.last_slctn = true inner join uspt_last_slctn_trget ulst on ulst.evl_last_slctn_id = uels.evl_last_slctn_id and ulst.apply_id = ubpa.apply_id and ulst.slctn = true inner join uspt_bsns_slctn ubs on ubs.last_slctn_trget_id = ulst.last_slctn_trget_id inner join uspt_bsns_plan_doc ubpd on ubpd.bsns_slctn_id = ubs.bsns_slctn_id inner join uspt_task_prtcmpny utp on utp.bsns_plan_doc_id = ubpd.bsns_plan_doc_id where ubpa.slctn = true
and utp.task_partcptn_entrprs_id in
#{item}
and 1 = 0

sql.where:
ubpa.member_id = #{memberId}

	and ubpa.rcept_sttus_cd = #{rceptSttusCd}




			and ubpat.task_nm_ko like concat('%', #{keyword}, '%')


			and ubp.pblanc_nm like concat('%', #{keyword}, '%')




	and ubpa.rcept_dt >= to_date(#{rceptDtStart}, 'yyyymmdd')


	and ubpa.rcept_dt <= to_date(#{rceptDtEnd}, 'yyyymmdd')

mapper.select:
/** UsptBsnsPblancApplcntDao.selectBsnsBasic */ select ubpa.apply_id , ub.bsns_cd , ub.bsns_nm , ub.bsns_year , ubp.pblanc_nm , ubp.bsns_bgnde , ubp.bsns_endde , ubpat.task_nm_ko as task_nm , ubpa.receipt_no , cm.member_nm , usb.bsns_type_cd , ubpa.member_id
, ubc.charger_author_cd
from uspt_bsns_pblanc_applcnt ubpa inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubpa.pblanc_id and ubpr.rcept_odr = ubpa.rcept_odr inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpr.pblanc_id inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd inner join uspt_stdr_bsns usb on usb.stdr_bsns_cd = ub.stdr_bsns_cd
inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId}
inner join cmmt_member cm on cm.member_id = ubpa.member_id where ubpa.apply_id = #{applyId}
